'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { motion, AnimatePresence } from "framer-motion";
import { 
  TrendingUp, 
  ArrowLeft, 
  Calendar, 
  Wallet, 
  PieChart, 
  Percent, 
  Loader2,
  CheckCircle2
} from 'lucide-react';

interface TimelineItem {
  month: number;
  totalValue: number;
  accumulatedProfit: number;
}

interface ObliczeniaWynik {
  daily: number;
  weekly: number;
  monthly: number;
  yearly: number;
  total: number;
  duration: number;
  timeline: TimelineItem[];
}

interface Obligacja {
  symbol: string;
  oprocentowaniePierwszyRok: number;
  okresLata: number;
  kapitalizacja: boolean;
}

export default function KalkulatorPage() {
  const [kwota, setKwota] = useState<number | ''>(1000);
  const [wybranySymbol, setWybranySymbol] = useState<string>('');
  const [listaObligacji, setListaObligacji] = useState<Obligacja[]>([]);
  const [wyniki, setWyniki] = useState<ObliczeniaWynik | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [loadingObligacje, setLoadingObligacje] = useState(true);

  const BACKEND_URL = 'http://localhost:8080/api';

  useEffect(() => {
    const fetchObligacje = async () => {
      try {
        const response = await fetch(`${BACKEND_URL}/obligacje`);
        if (!response.ok) throw new Error('Błąd pobierania listy.');
        const data: Obligacja[] = await response.json();
        setListaObligacji(data);
        if (data.length > 0) setWybranySymbol(data[0].symbol);
      } catch (e) {
        setError('Nie udało się połączyć z backendem (port 8080).');
      } finally {
        setLoadingObligacje(false);
      }
    };
    fetchObligacje();
  }, []);

  const handleOblicz = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setWyniki(null);

    if (!kwota || Number(kwota) <= 0 || !wybranySymbol) {
      setError('Podaj poprawną kwotę i wybierz obligację.');
      return;
    }

    setLoading(true);
    try {
      const url = `${BACKEND_URL}/calc?kwota=${kwota}&symbol=${wybranySymbol}`;
      const response = await fetch(url);
      if (!response.ok) {
        const txt = await response.text();
        throw new Error(txt || 'Błąd serwera');
      }
      const data: ObliczeniaWynik = await response.json();
      setWyniki(data);
    } catch (e: any) {
      console.error(e);
      setError('Błąd obliczeń. Sprawdź połączenie z serwerem.');
    } finally {
      setLoading(false);
    }
  };

  const formatPLN = (value: number | undefined) => {
    if (value === undefined) return '-';
    return new Intl.NumberFormat('pl-PL', { style: 'currency', currency: 'PLN' }).format(value);
  };

  const wybranaObligacjaInfo = listaObligacji.find(o => o.symbol === wybranySymbol);

  return (
    <div style={{ 
      fontFamily: '-apple-system, BlinkMacSystemFont, "Inter", sans-serif', 
      color: '#1D1D1F', 
      backgroundColor: '#F5F5F7', 
      minHeight: '100vh',
      paddingBottom: '80px'
    }}>
      
      <nav style={{ 
        padding: '20px', 
        display: 'flex', 
        justifyContent: 'center', 
        position: 'sticky', 
        top: 0, 
        zIndex: 100, 
        background: 'rgba(255,255,255,0.8)',
        backdropFilter: 'blur(20px)',
        borderBottom: '1px solid rgba(0,0,0,0.05)'
      }}>
        <div style={{ width: '100%', maxWidth: '980px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Link href="/" style={{ textDecoration: 'none', color: '#1D1D1F', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.9rem', fontWeight: 500 }}>
                <ArrowLeft size={18} /> Powrót
            </Link>
            <span style={{ fontWeight: 600, fontSize: '1.2rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                <TrendingUp size={20} color="#0071E3" /> Kalkulator
            </span>
            <div style={{ width: '60px' }}></div>
        </div>
      </nav>

      <div style={{ maxWidth: '800px', margin: '40px auto', padding: '0 20px' }}>
        
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
        >
          <div style={{ textAlign: 'center', marginBottom: '40px' }}>
            <h1 style={{ fontSize: '2.5rem', fontWeight: 700, letterSpacing: '-0.03em', marginBottom: '10px' }}>
              Symulacja zysków
            </h1>
            <p style={{ fontSize: '1.1rem', color: '#86868b' }}>
              Precyzyjne obliczenia uwzględniające podatek Belki (19%).
            </p>
          </div>

          <div style={cardStyle}>
            {loadingObligacje ? (
               <div style={{ padding: '40px', textAlign: 'center', color: '#86868b' }}>
                  <Loader2 className="animate-spin" style={{ margin: '0 auto 10px' }} />
                  Ładowanie danych...
               </div>
            ) : (
            <form onSubmit={handleOblicz}>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '24px' }}>
                
                <div>
                  <label style={labelStyle}>Kwota inwestycji (PLN)</label>
                  <div style={{ position: 'relative' }}>
                    <Wallet size={20} color="#86868b" style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)' }} />
                    <input
                      type="number"
                      value={kwota}
                      onChange={(e) => setKwota(e.target.value === '' ? '' : Number(e.target.value))}
                      placeholder="1000"
                      style={inputStyle}
                    />
                  </div>
                </div>

                <div>
                  <label style={labelStyle}>Rodzaj Obligacji</label>
                  <div style={{ position: 'relative' }}>
                    <PieChart size={20} color="#86868b" style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)' }} />
                    <select
                      value={wybranySymbol}
                      onChange={(e) => setWybranySymbol(e.target.value)}
                      style={inputStyle}
                    >
                      {listaObligacji.map(o => (
                        <option key={o.symbol} value={o.symbol}>{o.symbol}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              <AnimatePresence>
              {wybranaObligacjaInfo && (
                <motion.div 
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  style={{ 
                    marginTop: '24px', 
                    padding: '20px', 
                    borderRadius: '16px', 
                    background: '#F5F5F7',
                    display: 'flex',
                    flexWrap: 'wrap',
                    gap: '20px',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    fontSize: '0.95rem'
                  }}
                >
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <Percent size={18} color="#0071E3" />
                    <span>Oprocentowanie: <strong>{wybranaObligacjaInfo.oprocentowaniePierwszyRok}%</strong></span>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                     <Calendar size={18} color="#0071E3" />
                     <span>Czas trwania: <strong>{wybranaObligacjaInfo.okresLata} lat</strong></span>
                  </div>
                </motion.div>
              )}
              </AnimatePresence>

              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                type="submit"
                disabled={loading}
                style={{
                  marginTop: '30px',
                  width: '100%',
                  padding: '18px',
                  backgroundColor: '#0071E3',
                  color: 'white',
                  border: 'none',
                  borderRadius: '16px',
                  fontSize: '1.1rem',
                  fontWeight: 600,
                  cursor: loading ? 'not-allowed' : 'pointer',
                  opacity: loading ? 0.7 : 1,
                  boxShadow: '0 4px 12px rgba(0, 113, 227, 0.3)'
                }}
              >
                {loading ? (
                    <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
                        <Loader2 className="animate-spin" size={20}/> Obliczam...
                    </span>
                ) : 'Oblicz potencjalny zysk'}
              </motion.button>

              {error && (
                <p style={{ color: '#FF3B30', marginTop: '15px', textAlign: 'center', fontSize: '0.9rem' }}>{error}</p>
              )}
            </form>
            )}
          </div>
        </motion.div>

        <AnimatePresence>
          {wyniki && (
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2 }}
              style={{ marginTop: '40px' }}
            >
              <h2 style={{ fontSize: '1.5rem', fontWeight: 600, marginBottom: '24px' }}>Twoja prognoza</h2>
              
              <div style={{ 
                display: 'grid', 
                gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', 
                gap: '20px',
                marginBottom: '40px'
              }}>
                 <ResultWidget label="Zysk Dzienny" value={formatPLN(wyniki.daily)} delay={0.1} />
                 <ResultWidget label="Zysk Miesięczny" value={formatPLN(wyniki.monthly)} delay={0.2} />
                 <ResultWidget label="Zysk Roczny (śr.)" value={formatPLN(wyniki.yearly)} delay={0.3} />
                 <motion.div 
                    initial={{ scale: 0.9, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ delay: 0.4 }}
                    style={{ 
                        gridColumn: '1 / -1', // Rozciągnij na całość
                        background: 'linear-gradient(135deg, #0071E3 0%, #00C7BE 100%)',
                        padding: '30px',
                        borderRadius: '24px',
                        color: 'white',
                        boxShadow: '0 10px 30px rgba(0, 113, 227, 0.3)',
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        flexWrap: 'wrap',
                        gap: '20px'
                    }}
                 >
                    <div>
                        <p style={{ opacity: 0.9, fontSize: '0.95rem', marginBottom: '5px' }}>Zysk całkowity, po dacie zapadalności obligacji.</p>
                        <h3 style={{ fontSize: '2.5rem', fontWeight: 700, letterSpacing: '-0.02em' }}>{formatPLN(wyniki.total)}</h3>
                    </div>
                    <div style={{ background: 'rgba(255,255,255,0.2)', padding: '10px 20px', borderRadius: '12px', backdropFilter: 'blur(10px)' }}>
                        <span style={{ fontSize: '0.9rem', fontWeight: 600 }}>Po {wyniki.duration} latach</span>
                    </div>
                 </motion.div>
              </div>

              <div style={{ ...cardStyle, padding: '0', overflow: 'hidden' }}>
                <div style={{ padding: '24px', borderBottom: '1px solid #eee' }}>
                    <h3 style={{ fontSize: '1.2rem', fontWeight: 600 }}>Harmonogram wzrostu</h3>
                </div>
                <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '600px' }}>
                        <thead>
                            <tr style={{ background: '#F5F5F7', textAlign: 'left', color: '#86868b', fontSize: '0.85rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                                <th style={{ padding: '16px 24px', fontWeight: 600 }}>Miesiąc</th>
                                <th style={{ padding: '16px 24px', fontWeight: 600 }}>Stan Konta</th>
                                <th style={{ padding: '16px 24px', fontWeight: 600, textAlign: 'right' }}>Zysk Netto</th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr style={{ borderBottom: '1px solid #f0f0f0' }}>
                                <td style={{ padding: '16px 24px', color: '#86868b' }}>Start</td>
                                <td style={{ padding: '16px 24px', fontWeight: 500 }}>{formatPLN(Number(kwota))}</td>
                                <td style={{ padding: '16px 24px', textAlign: 'right', color: '#86868b' }}>-</td>
                            </tr>
                            {wyniki.timeline.map((item) => (
                                <tr key={item.month} style={{ borderBottom: '1px solid #f5f5f5' }}>
                                    <td style={{ padding: '16px 24px', color: '#1D1D1F' }}>{item.month}</td>
                                    <td style={{ padding: '16px 24px', color: '#1D1D1F' }}>{formatPLN(item.totalValue)}</td>
                                    <td style={{ padding: '16px 24px', textAlign: 'right', color: '#34C759', fontWeight: 600 }}>
                                        +{formatPLN(item.accumulatedProfit)}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
              </div>

            </motion.div>
          )}
        </AnimatePresence>

      </div>
    </div>
  );
}


function ResultWidget({ label, value, delay }: { label: string, value: string, delay: number }) {
    return (
        <motion.div 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay }}
            style={{
                background: '#FFFFFF',
                borderRadius: '20px',
                padding: '24px',
                boxShadow: '0 4px 20px rgba(0,0,0,0.02)',
                border: '1px solid rgba(0,0,0,0.03)',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center'
            }}
        >
            <span style={{ fontSize: '0.85rem', color: '#86868b', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '8px' }}>
                {label}
            </span>
            <span style={{ fontSize: '1.6rem', fontWeight: 600, color: '#1D1D1F' }}>
                {value}
            </span>
        </motion.div>
    )
}

const cardStyle: React.CSSProperties = {
  background: '#FFFFFF',
  borderRadius: '24px',
  boxShadow: '0 10px 40px rgba(0,0,0,0.04)',
  padding: '32px',
  border: '1px solid rgba(0,0,0,0.02)'
};

const labelStyle: React.CSSProperties = {
  display: 'block',
  marginBottom: '10px',
  fontSize: '0.9rem',
  fontWeight: '600',
  color: '#424245',
  marginLeft: '4px'
};

const inputStyle: React.CSSProperties = {
  width: '100%',
  padding: '16px 16px 16px 48px',
  fontSize: '1.1rem',
  borderRadius: '16px',
  border: '1px solid transparent',
  backgroundColor: '#F5F5F7',
  color: '#1D1D1F',
  outline: 'none',
  transition: 'all 0.2s',
  appearance: 'none',
  cursor: 'pointer'
};